export default "const clockDemoJob: SchedulerModule = {\n  id: \"clockDemo\",\n  async run(ctx) {\n    const now = new Date();\n    const isoTime = now.toISOString();\n    const timeLabel = formatTimeLabel(now);\n\n    await ctx.eventBus?.emitAsync(\n      SCHEDULER_TICK_EVENT,\n      createEventPayload(CLOCK_JOB_SOURCE, {\n        isoTime,\n        jobName: \"clockDemo\",\n        source: \"scheduler\",\n        timeLabel\n      })\n    );\n  }\n};\n"